#!/usr/bin/env node
// apply-daycare-enrichment.mjs
// Reads data/scraped/enrich-daycare.json and emits db/migrations/007_populate_daycare_min_age.sql
// Devin runs the SQL in the Supabase SQL editor.

import { readFileSync, writeFileSync } from "node:fs";

const enrich = JSON.parse(readFileSync("data/scraped/enrich-daycare.json", "utf8"));
const esc = (s) => s == null ? "NULL" : `'${String(s).replace(/'/g, "''")}'`;

const lines = [
  "-- 007_populate_daycare_min_age.sql",
  "-- Generated by scripts/apply-daycare-enrichment.mjs",
  "-- Populates the daycare_min_age column from LLM-researched data.",
  "",
  "BEGIN;",
  "",
];

let written = 0;
for (const r of enrich) {
  if (!r.daycare_min_age) continue;
  // Store source_url in the existing daycare_url column.
  // COALESCE so we don't overwrite any manually-curated URL already in the DB.
  const sets = [`daycare_min_age = ${esc(r.daycare_min_age)}`];
  if (r.source_url) {
    sets.push(`daycare_url = COALESCE(daycare_url, ${esc(r.source_url)})`);
  }
  lines.push(
    `UPDATE resorts SET ${sets.join(", ")} ` +
    `WHERE name = ${esc(r.name)} AND pass_type = ${esc(r.pass_type)} AND location = ${esc(r.location)};`,
  );
  written++;
}

lines.push("", "COMMIT;", "");
writeFileSync("db/migrations/007_populate_daycare_min_age.sql", lines.join("\n"));
console.log(`wrote ${written} UPDATE statements to db/migrations/007_populate_daycare_min_age.sql`);
